effect.shader:
void main() {
    vec2 pixelSize = 1.0/getTexSize(inputImg.size);
    vec2 tiledCoord = acLayerNorm;
    if( vertoffs ) {
        tiledCoord.y += step(1., mod(tiledCoord.x,2.0)) * phase;
    } else {
        tiledCoord.x += step(1., mod(tiledCoord.y,2.0)) * phase;
    }
    if(mirror) {
        tiledCoord = abs(mod(tiledCoord-vec2(1.0,1.0),vec2(2.0,2.0))-vec2(1.0,1.0));
    } else {
        tiledCoord = mod(tiledCoord,vec2(1.0,1.0));
    }
    float a = angle * 0.0174533;
    mat2 rot = mat2(
        cos(a), -sin(a),
        sin(a), cos(a)
    );
    vec2 scaledCoord = tiledCoord;
    scaledCoord -= vec2(0.5,0.5);
    scaledCoord *= vec2(1.0)/(scale+pixelSize*4.0);
    scaledCoord.x *= acLayerSize.x / acLayerSize.y;
    scaledCoord *= rot;
    scaledCoord.x *= acLayerSize.y / acLayerSize.x;
    scaledCoord += vec2(0.5,0.5);

    gl_FragColor = texture2DCv(inputImg.texture,(vec4(scaledCoord,0.0,1.0)*acLayerToScreen).xy);
}
